  ('public-health-specialist-moex-01009', 'public-health-specialist', 'public-health-specialist-moex-110-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '下圖為總共50位病人的存活曲線，虛線為男性，實線為女性，跨在每條線上的小細直線標示 為設限（censor）。有關存活曲線，下列敘述何者正確？', '["若病人在2000天時設限，表示此病人在第2000天時死亡", "女性存活時間的中位數約落在1000天到1700天之間", "女性存活時間的中位數比男性長", "男性組無法估算存活時間的中位數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "8cc212619220", "answer_pdf_sha1": "4c6140f93ee8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
